/* Tabler.io JS — vendored minimal implementation for event-spec admin UI */
(function(){
"use strict";

// Auto-close alerts with [data-dismiss]
document.addEventListener("DOMContentLoaded",function(){
  document.querySelectorAll("[data-dismiss='alert']").forEach(function(btn){
    btn.addEventListener("click",function(){
      var alert=btn.closest(".es-alert");
      if(alert)alert.remove();
    });
  });

  // Close modal on overlay click
  document.querySelectorAll(".es-modal-overlay").forEach(function(overlay){
    overlay.addEventListener("click",function(e){
      if(e.target===overlay)overlay.remove();
    });
  });
});
})();
